import { EventAdapter, onClickAdapter } from './coding';

describe('EventAdapter', () => {
  let eventAdapter: EventAdapter;

  beforeEach(() => {
    eventAdapter = new EventAdapter();
  });

  describe('Basic Event Registration', () => {
    test('should register click listener', () => {
      const listener = jest.fn();
      eventAdapter.setOnClickListener('button1', listener);
      
      expect(eventAdapter.hasListeners('button1')).toBe(true);
    });

    test('should trigger click listener', () => {
      const listener = jest.fn();
      eventAdapter.setOnClickListener('button1', listener);
      
      eventAdapter.triggerClick('button1');
      
      expect(listener).toHaveBeenCalledTimes(1);
    });

    test('should pass view to listener', () => {
      const listener = jest.fn();
      const mockView = { id: 'button1' };
      
      eventAdapter.setOnClickListener('button1', listener);
      eventAdapter.triggerClick('button1', mockView);
      
      expect(listener).toHaveBeenCalledWith(mockView);
    });
  });

  describe('Multiple Listeners', () => {
    test('should support multiple listeners on same view', () => {
      const listener1 = jest.fn();
      const listener2 = jest.fn();
      const listener3 = jest.fn();
      
      eventAdapter.setOnClickListener('button1', listener1);
      eventAdapter.setOnClickListener('button1', listener2);
      eventAdapter.setOnClickListener('button1', listener3);
      
      eventAdapter.triggerClick('button1');
      
      expect(listener1).toHaveBeenCalledTimes(1);
      expect(listener2).toHaveBeenCalledTimes(1);
      expect(listener3).toHaveBeenCalledTimes(1);
    });

    test('should return correct listener count', () => {
      eventAdapter.setOnClickListener('button1', jest.fn());
      eventAdapter.setOnClickListener('button1', jest.fn());
      
      expect(eventAdapter.getListenerCount('button1')).toBe(2);
    });
  });

  describe('Listener Removal', () => {
    test('should remove specific listener', () => {
      const listener1 = jest.fn();
      const listener2 = jest.fn();
      
      eventAdapter.setOnClickListener('button1', listener1);
      eventAdapter.setOnClickListener('button1', listener2);
      
      eventAdapter.removeOnClickListener('button1', listener1);
      eventAdapter.triggerClick('button1');
      
      expect(listener1).not.toHaveBeenCalled();
      expect(listener2).toHaveBeenCalledTimes(1);
    });

    test('should remove all listeners for view', () => {
      eventAdapter.setOnClickListener('button1', jest.fn());
      eventAdapter.setOnClickListener('button1', jest.fn());
      
      eventAdapter.removeAllListeners('button1');
      
      expect(eventAdapter.hasListeners('button1')).toBe(false);
      expect(eventAdapter.getListenerCount('button1')).toBe(0);
    });

    test('should handle removing non-existent listener', () => {
      const listener = jest.fn();
      
      expect(() => {
        eventAdapter.removeOnClickListener('button1', listener);
      }).not.toThrow();
    });
  });

  describe('View Object Binding', () => {
    test('should bind listener to view object', () => {
      const mockView = {
        onClick: jest.fn()
      };
      const listener = jest.fn();
      
      eventAdapter.setOnClickListenerForView(mockView, listener);
      
      expect(mockView.onClick).toHaveBeenCalled();
    });

    test('should trigger view-bound listener', () => {
      let capturedCallback: (() => void) | null = null;
      const mockView = {
        onClick: (callback: () => void) => {
          capturedCallback = callback;
        }
      };
      const listener = jest.fn();
      
      eventAdapter.setOnClickListenerForView(mockView, listener);
      
      // Simulate HarmonyOS triggering the click
      if (capturedCallback) {
        capturedCallback();
      }
      
      expect(listener).toHaveBeenCalledWith(mockView);
    });
  });

  describe('Edge Cases', () => {
    test('should handle trigger with no listeners', () => {
      expect(() => {
        eventAdapter.triggerClick('nonexistent');
      }).not.toThrow();
    });

    test('should handle empty view ID', () => {
      const listener = jest.fn();
      eventAdapter.setOnClickListener('', listener);
      
      eventAdapter.triggerClick('');
      
      expect(listener).toHaveBeenCalled();
    });

    test('should clear all listeners', () => {
      eventAdapter.setOnClickListener('button1', jest.fn());
      eventAdapter.setOnClickListener('button2', jest.fn());
      
      eventAdapter.clear();
      
      expect(eventAdapter.hasListeners('button1')).toBe(false);
      expect(eventAdapter.hasListeners('button2')).toBe(false);
    });
  });

  describe('onClickAdapter Helper', () => {
    test('should create adapter function', () => {
      const listener = jest.fn();
      const adapter = onClickAdapter(listener);
      
      adapter();
      
      expect(listener).toHaveBeenCalled();
    });

    test('should pass view through adapter', () => {
      const listener = jest.fn();
      const adapter = onClickAdapter(listener);
      const mockView = { id: 'test' };
      
      adapter(mockView);
      
      expect(listener).toHaveBeenCalledWith(mockView);
    });
  });
});

